def sjf_non_preemptive(processes):
 processes.sort(key=lambda x: (x['arrival'], x['burst']))
 current_time = 0
 total_wait = 0

 for p in processes:
 if current_time < p['arrival']:
 current_time = p['arrival']
 p['wait'] = current_time - p['arrival']
 total_wait += p['wait']
 current_time += p['burst']
 p['turnaround'] = current_time - p['arrival']

 return total_wait / len(processes)

# Example usage:
processes = [
 {'id': 1, 'arrival': 0, 'burst': 6},
 {'id': 2, 'arrival': 2, 'burst': 8},
 {'id': 3, 'arrival': 4, 'burst': 7}
]
print(f"Average waiting time: {sjf_non_preemptive(processes)}")

#include <stdio.h>

struct Process {
 int pid;
 int arrival;
 int burst;
 int priority;
};

void priority_schedule(struct Process p[], int n) {
 int wait[n], tat[n];
 int total_wait = 0;

 // Sort by priority (ascending) and arrival time
 for(int i=0; i<n-1; i++) {
 for(int j=0; j<n-i-1; j++) {
 if(p[j].priority > p[j+1].priority || 
 (p[j].priority == p[j+1].priority && p[j].arrival > p[j+1].arrival)) {
 struct Process temp = p[j];
 p[j] = p[j+1];
 p[j+1] = temp;
 }
 }
 }

 int current_time = 0;
 for(int i=0; i<n; i++) {
 if(current_time < p[i].arrival)
 current_time = p[i].arrival;

 wait[i] = current_time - p[i].arrival;
 total_wait += wait[i];
 current_time += p[i].burst;
 tat[i] = current_time - p[i].arrival;
 }

 printf("Average waiting time: %.2f\n", (float)total_wait/n);
}

int main() {
 struct Process procs[] = {{1,0,10,3}, {2,2,5,1}, {3,4,8,2}};
 priority_schedule(procs, 3);
 return 0;
}
